  ('dietitian-moex-04121', 'dietitian', 'dietitian-moex-114-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '在pH 7.0溶液中，下列何種胺基酸帶負電荷？', '["離胺酸（lysine）", "組胺酸（histidine）", "精胺酸（arginine）", "天門冬胺酸（aspartate）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:34+00:00", "source_pdf_sha1": "6711d3d5b971", "answer_pdf_sha1": "97790a8d5dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "101", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
